import parser from 'sql-parse';
export const isSqlQuery = (literal, ignorePattern) => {
    if (!literal) {
        return false;
    }
    let maybeSql = literal;
    if (ignorePattern) {
        maybeSql = maybeSql.replaceAll(new RegExp(ignorePattern, 'gu'), 'foo');
    }
    try {
        parser.parse(maybeSql);
    }
    catch (_a) {
        return false;
    }
    return true;
};
